const INSURANCE_VALUE: Record<string, number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
  rune: 250,
  moonstone: 250,
};

const DEDUCTIBLE = 100;

export function claim(policy: Item[], incident: Incident): ClaimResult {
  const payout = incident.damages.reduce(
    (sum, damage) => sum + (damage.amount - DEDUCTIBLE),
    0
  );

  const insuranceSum = policy.reduce(
    (sum, item) => sum + INSURANCE_VALUE[item.type],
    0
  );
  const cap = 2 * insuranceSum;
  const remainingCap = cap - payout;

  return { payout, remainingCap };
}
